pipeline.evaluate:
(() => {
  const items = [];
  document.querySelectorAll('.crayons-story').forEach(story => {
    const titleEl = story.querySelector('h2 a, h3 a');
    if (titleEl) {
      items.push({
        title: titleEl.textContent.trim(),
        url: 'https://dev.to' + titleEl.getAttribute('href')
      });
    }
  });
  return items;
})()
